#include <stdio.h>
#include <stdlib.h>

typedef struct {
    float rto_hours;      // Recovery Time Objective
    float rpo_hours;     // Recovery Point Objective
    float data_change_rate;  // GB changed per hour
    int criticality;     // 1=low, 2=medium, 3=high
} BusinessRequirements;

typedef struct {
    char strategy[50];
    float cost_per_month;
    float rto_achieved;
    float rpo_achieved;
} BackupStrategy;

void recommendStrategy(BusinessRequirements req) {
    BackupStrategy strategies[] = {
        {"Daily Backup", 100, 24, 24},
        {"Hourly Backup", 300, 4, 1},
        {"Real-time Replication", 2000, 0.5, 0.01}
    };

    printf("Business Requirements:\n");
    printf("  RTO: %.1f hours, RPO: %.1f hours\n", req.rto_hours, req.rpo_hours);
    printf("  Data change rate: %.1f GB/hour\n\n", req.data_change_rate);

    printf("Recommended Strategy:\n");
    for(int i = 0; i < 3; i++) {
        if(strategies[i].rto_achieved <= req.rto_hours && 
           strategies[i].rpo_achieved <= req.rpo_hours) {
            printf("  %s - $%.0f/month\n", 
                   strategies[i].strategy, strategies[i].cost_per_month);
            printf("  Achieves RTO: %.1f hrs, RPO: %.2f hrs\n",
                   strategies[i].rto_achieved, strategies[i].rpo_achieved);
            break;
        }
    }
}

int main() {
    BusinessRequirements req = {4.0, 1.0, 10.0, 3};
    recommendStrategy(req);
    return 0;
}

import java.time.LocalDateTime;
import java.util.*;

public class SLAMetricsCollector {
    private Map<String, List<Double>> metricHistory = new HashMap<>();
    private Map<String, Double> slaTargets = new HashMap<>();

    public void setSLATarget(String metricName, double target) {
        slaTargets.put(metricName, target);
        metricHistory.put(metricName, new ArrayList<>());
    }

    public void recordMetric(String metricName, double value) {
        metricHistory.get(metricName).add(value);
    }

    public Map<String, Boolean> checkCompliance() {
        Map<String, Boolean> results = new HashMap<>();

        for (String metric : metricHistory.keySet()) {
            List<Double> values = metricHistory.get(metric);
            double average = values.stream()
                .mapToDouble(Double::doubleValue)
                .average()
                .orElse(0.0);

            double target = slaTargets.get(metric);
            boolean compliant = average >= target;
            results.put(metric, compliant);

            if (!compliant) {
                logViolation(metric, average, target);
            }
        }
        return results;
    }

    private void logViolation(String metric, double actual, double target) {
        System.out.println("[" + LocalDateTime.now() + "] " +
            "SLA VIOLATION: " + metric + " | " +
            "Target: " + target + " | " +
            "Actual: " + String.format("%.2f", actual));
    }

    public static void main(String[] args) {
        SLAMetricsCollector collector = new SLAMetricsCollector();

        // Set SLA targets
        collector.setSLATarget("availability", 99.9);
        collector.setSLATarget("response_time_ms", 200.0);
        collector.setSLATarget("error_rate", 0.1);

        // Record sample metrics
        collector.recordMetric("availability", 99.8);
        collector.recordMetric("response_time_ms", 180.0);
        collector.recordMetric("error_rate", 0.05);

        // Check compliance
        Map<String, Boolean> results = collector.checkCompliance();
        results.forEach((k, v) -> 
            System.out.println(k + ": " + (v ? "COMPLIANT" : "VIOLATION")));
    }
}
